Let's start with the backend. The following code will be added to the `index.js` in the `routes` folder.

After importing some libraries and checking for some environment variables, import the Vonage SDKs needed and initialize instances with credentials:

```js
import { Vonage } from '@vonage/server-sdk';
import { Video } from '@vonage/video';

const vonageCredentials = {
  applicationId: appId,
  privateKey: privateKey
};
const vonage = new Vonage(vonageCredentials);
vonage.video = new Video(vonageCredentials);
```

Next, the routes related to Archiving will be added.

A `POST` request to `/archive/start` will create and start an archive with the session ID that is passed in. This route returns the archive object to the frontend.

```js
/**
 * POST /archive/start
 */
router.post('/archive/start', async function (req, res) {
  console.log('attempting to start archive');
  const json = req.body;
  const sessionId = json.sessionId;
  const archiveOptions = {
    name: findRoomFromSessionId(sessionId),
  };
  try {
    const archive = await vonage.video.startArchive(sessionId, archiveOptions);
    console.log("archive: ", archive);
    res.setHeader('Content-Type', 'application/json');
    res.send(archive);
  } catch (error){
    console.error("error starting archive: ",error);
    res.status(500).send({ error: 'startArchive error:' + error });
  }
});
```

To stop an archive, a `POST` request will be made to the `/archive/:archiveId/stop` where `:archiveId` is the ID of the archive that was started with the previous route. This endpoint return the archive object:

```js
/**
 * POST /archive/:archiveId/stop
 */
router.post('/archive/:archiveId/stop', async function (req, res) {
  const archiveId = req.params.archiveId;
  console.log('attempting to stop archive: ' + archiveId);
  try {
    const archive = await vonage.video.stopArchive(archiveId);
    res.setHeader('Content-Type', 'application/json');
    res.send(archive);
  } catch (error){
    console.error("error stopping archive: ",error);
    res.status(500).send({ error: 'stopArchive error:', error });
  }
});
```


Sending a `GET` request to `/archive/:archiveId/view` will return the URL of the recording of the archive that matches the ID (`archiveId`) if it is available, otherwise it will show a page that says 'Archiving Pending'.

```js
/**
 * GET /archive/:archiveId/view
 */
router.get('/archive/:archiveId/view', async function (req, res) {
  const archiveId = req.params.archiveId;
  console.log('attempting to view archive: ' + archiveId);
  try {
    const archive = await vonage.video.getArchive(archiveId);
    if (archive.status === 'available') {
      res.redirect(archive.url);
    } else {
      res.render('view', { title: 'Archiving Pending' });
    }
  } catch (error){
    console.log("error viewing archive: ",error);
    res.status(500).send({ error: 'viewArchive error:' + error });
  }
});
```

Send a `GET` request to `/archive/:archiveId` where `:archiveid` is the ID of the archive you'd like to get information for:

```js
/**
 * GET /archive/:archiveId
 */
router.get('/archive/:archiveId', async function (req, res) {
  const archiveId = req.params.archiveId;
  // fetch archive
  console.log('attempting to fetch archive: ' + archiveId);
  try {
    const archive = await vonage.video.getArchive(archiveId);
    // extract as a JSON object
    res.setHeader('Content-Type', 'application/json');
    res.send(archive);
  } catch (error){
    console.error("error getting archive: ",error);
    res.status(500).send({ error: 'getArchive error:' + error });
  }
});
```

To get a list of archives for the session returned to the frontend, send a `GET` request to `/archive` with the queries for `count`, `offset` and `sessionId`:

```js
/**
 * GET /archive
 */
router.get('/archive', async function (req, res) {
  let filter = {};
  if (req.query.count) {
    filter.count = req.query.count;
  }
  if (req.query.offset) {
    filter.offset = req.query.offset;
  }
  if (req.query.sessionId) {
    filter.sessionId = req.query.sessionId;
  }
  // list archives
  console.log('attempting to list archives');
  try {
    const archives = await vonage.video.searchArchives(filter);
    // extract as a JSON object
    res.setHeader('Content-Type', 'application/json');
    res.send(archives);
  } catch (error){
    console.error("error listing archives: ",error);
    res.status(500).send({ error: 'listArchives error:' + error });
  }
});
```

Next, let's add some functionality to the application.

The following code snippets will be added to the `app.js` file in the `js` folder.


Initialize an `archive` and get references to the archive UI elements and set the display of the stop button to none:

```js
let archive;
const archiveStartBtn = document.querySelector('#start');
const archiveStopBtn = document.querySelector('#stop');
const archiveLinkSpan = document.querySelector('#archiveLink');

archiveStopBtn.style.display = "none";
```

In the `initializeSession()` function, add an event listener to the session for `archiveStarted` that will set the `archive` variable to the current archive object, update the displays of the buttons and clear the archive link's space:

```js
session.on('archiveStarted', (event) => {
  archive = event;
  console.log('Archive started ' + archive.id);
  archiveStartBtn.style.display = 'none';
  archiveStopBtn.style.display = 'inline';
  archiveLinkSpan.innerHTML = '';
});
```

Next, add an event listener to the session for when the archive is stopped (`archiveStopped`) that will update the buttons' displays and insert a link to view the recording:

```js
session.on('archiveStopped', (event) => {
  archive = event;
  console.log('Archive stopped ' + archive.id);
  archiveStartBtn.style.display = 'inline';
  archiveStopBtn.style.display = 'none';
  archiveLinkSpan.innerHTML = `<a href="/archive/${archive.id}/view" target="_blank">View Archive</a>`;
});
```

Below `initializeSession()`, add a function that can be called to make `POST` requests to the endpoints:

```js
async function postData(url='', data={}){
  try {
    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(data)
    });
    if (!response.ok){
      throw new Error('error getting data!');
    }
    return response.json();
  }
  catch (error){
    handleError(error);
  }
}
```

Pressing the start button will call the `startArchiving()` function to make a `POST` request to `/archive/start` passing the `sessionId` and if the status that returns does not equal `started`, send the error to the `handleError` function:

```js
async function startArchiving(){
  console.log('start archiving');
  try {
    archive = await postData('/archive/start',{sessionId});
    console.log('archive started: ', archive);
    if (archive.status !== 'started'){
      handleError(archive.error);
    } else {
      console.log('successfully started archiving: ',archive);
    }
  }
  catch(error){
    handleError(error);
  }
}

archiveStartBtn.addEventListener('click', startArchiving, false);
```


Pressing the stop button will call the `stopArchiving()` function to make a `POST` request to the stop archiving endpoint with the archive ID inserted to the backend and if the status that returns does not equal `stopped`, send the error to the `handleError` function:

```js
async function stopArchiving(){
  console.log('stop archiving');
  try {
    archive = await postData(`/archive/${archive.id}/stop`,{});
    console.log('archive stopped: ', archive);
    if (archive.status !== 'stopped'){
      handleError(archive.error);
    } else {
      console.log('successfully stopped archiving: ',archive);
    }
  }
  catch(error){
    handleError(error);
  }
}

archiveStopBtn.addEventListener('click', stopArchiving, false);
```

